-- {"operators": "CTE,INNER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ORDER_LINE,WAREHOUSE"}
WITH district_revenue AS (SELECT OL_W_ID, OL_D_ID, SUM(OL_AMOUNT) AS total_revenue, COUNT(*) AS line_count, MIN(OL_AMOUNT) AS min_amt, MAX(OL_AMOUNT) AS max_amt FROM ORDER_LINE GROUP BY OL_W_ID, OL_D_ID) SELECT w.W_ID, w.W_NAME, w.W_TAX, w.W_YTD, dr.OL_D_ID, dr.total_revenue, dr.line_count, dr.min_amt, dr.max_amt, dr.total_revenue / NULLIF(dr.line_count, 0) AS avg_line_revenue, dr.total_revenue * (1 + w.W_TAX) AS taxed_revenue FROM WAREHOUSE w JOIN district_revenue dr ON w.W_ID = dr.OL_W_ID;
